/**
 * 类efuAI用于处理AI生成内容的相关功能
 */
class efuAI {
  /**
   * 构造函数，初始化类的属性
   */
  constructor() {
    this.root = "https://summary.tianli0.top"; // API根路径
    this.aiTalkMode = false; // AI对话模式开关
    this.aiPostExplanation = ''; // AI生成的内容
    this.config = GLOBAL_CONFIG.post_ai; // AI配置
    this.scoGPTIsRunning = false; // 当前是否正在运行生成任务
  }

  /**
   * 初始化功能，用于准备和启动AI相关功能
   */
  init() {
    if (!document.querySelector(".ai-explanation")) return; // 检查是否存在AI解释的容器

    this.scoGPTIsRunning = false; // 重置运行状态
    this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false; // 获取预设的AI内容

    if (!this.aiPostExplanation) {
      this.generate(); // 如果没有预设内容，则生成AI内容
    } else {
      this.aiShowAnimation(Promise.resolve(this.aiPostExplanation)); // 如果有预设内容，则直接显示
    }

    this.AIEngine(); // 初始化AI引擎
  }

  /**
   * 获取文章的标题和内容的摘要，用于生成AI内容
   * @returns {string} 拼接后的标题和内容摘要
   */
  getTitleAndContent() {
    const e = document.getElementById("article-container");
    const t = document.title;
    const n = e.getElementsByTagName("p");
    const i = e.querySelectorAll("h1, h2, h3, h4, h5");

    return (
      t +
      " " +
      Array.from(i)
        .concat(Array.from(n))
        .map((e) => e.innerText.replace(/https?:\/\/[^\s]+/g, ""))
        .join(" ")
    ).slice(0, 1e3);
  }

  /**
   * 生成AI内容
   */
  async generate() {
    this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent(), this.config.key));
  }

  /**
   * 发起网络请求，获取AI生成的内容
   * @param {string} e 文章标题
   * @param {string} t 文章内容摘要
   * @param {string} n API密钥
   * @returns {Promise<string>} 返回AI生成的内容或错误信息
   */
  async fetch(e, t, n) {
    const i = `${this.root}/?content=${encodeURIComponent(
      t
    )}&title=${e}&key=${encodeURIComponent(n)}&url=${encodeURIComponent(
      window.location.href
    )}`;
    const s = await fetch(i);
    const o = await s.json();

    return s.ok
      ? (this.aiPostExplanation = o.summary, o.summary)
      : (console.error("Request failed:", o.err_msg), o.err_msg);
  }

  /**
   * 显示AI生成内容的动画效果
   * @param {Promise<string>} e AI内容的Promise对象
   * @param {boolean} t 是否显示建议内容
   */
  aiShowAnimation(e, t = false) {
    const n = document.querySelector(".ai-explanation");
    const i = document.querySelector(".ai-tag");

    if (!n || this.scoGPTIsRunning) return; // 检查解释容器是否存在或是否正在运行

    this.scoGPTIsRunning = true; // 设置正在运行状态
    this.cleanSuggestions(); // 清除之前的建议内容
    i.classList.add("loadingAI"); // 添加加载中的样式
    n.style.display = "block";
    n.innerHTML = '生成中...<span class="blinking-cursor"></span>';

    let s, o, a = true, c = 0, r = true;
    const l = new IntersectionObserver(
      (e) => {
        a = e[0].isIntersecting;
        a && requestAnimationFrame(o);
      },
      { threshold: 0 }
    );

    e.then((e) => {
      s = performance.now();
      o = () => {
        if (c < e.length && a) {
          const r = performance.now();
          const g = r - s;
          const h = e.slice(c, c + 1);
          const u = /[，。！、？,.!?]/.test(h);
          const m = /[a-zA-Z0-9]/.test(h);

          g >= (u ? 100 * Math.random() + 100 : m ? 10 : 25) &&
            (n.innerText = e.slice(0, c + 1),
            s = r,
            c++,
            c < e.length
              ? (n.innerHTML = e.slice(0, c) + '<span class="blinking-cursor"></span>')
              : (n.innerHTML = e,
                n.style.display = "block",
                this.scoGPTIsRunning = false,
                i.classList.remove("loadingAI"),
                l.disconnect(),
                t && this.createSuggestions()),
            a && requestAnimationFrame(o));
        }
      };

      a && r && setTimeout(() => {
        requestAnimationFrame(o);
        r = false;
      }, 3e3);

      l.observe(n);
    }).catch((e) => {
      console.error("检索信息失败：", e);
      n.innerHTML = "检索信息失败";
      n.style.display = "block";
      this.scoGPTIsRunning = false;
      i.classList.remove("loadingAI");
      l.disconnect();
    });
  }

  /**
   * 初始化AI引擎，添加事件监听器
   */
  AIEngine() {
    const e = document.querySelector(".ai-tag");
    e &&
      e.addEventListener("click", () => {
        this.scoGPTIsRunning ||
          (this.aiTalkMode = true,
          this.aiShowAnimation(Promise.resolve(this.config.talk), true));
      });
  }

  /**
   * 清除建议内容
   */
  cleanSuggestions() {
    const e = document.querySelector(".ai-suggestions");
    e ? e.innerHTML = "" : console.error("没有这个元素：'ai-suggestions'");
  }

  /**
   * 创建建议内容
   */
  createSuggestions() {
    this.aiTalkMode &&
      (this.cleanSuggestions(),
      this.createSuggestionItemWithAction(
        "这篇文章讲了什么？",
        () => {
          "" === this.aiPostExplanation
            ? this.generate()
            : this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
        }
      ),
      this.config.randomPost &&
        this.createSuggestionItemWithAction(
          "带我去看看其他文章",
          () => toRandomPost()
        ),
      (this.aiTalkMode = true));
  }

  /**
   * 创建带有操作的建议项
   * @param {string} e 建议项的内容
   * @param {Function} t 点击建议项时执行的函数
   */
  createSuggestionItemWithAction(e, t) {
    const n = document.querySelector(".ai-suggestions");
    if (!n) return void console.error("无法找到具有class为ai-suggestions的元素");

    const i = document.createElement("div");
    i.classList.add("ai-suggestions-item");
    i.textContent = e;
    i.addEventListener("click", t);
    n.appendChild(i);
  }
}

const efu_ai = new efuAI(); // 创建efuAI实例